export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "17:02。灣岸署。物件確認室。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一間不大的房間。灰牆。日光燈。一張桌子。兩把椅子。角落有一台相機腳架。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "承辦刑警坐在對面。桌上放著一張表格和一支筆。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "朝倉小姐。今天的程序是自願物件確認。不是扣押。不是搜索。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "警方需要確認這件物品與匿名訊息及朝倉悠真相關文件的關係。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "本次預定拍照、測量與表面觀察。不進行破壞性檢查。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "如果需要留置，必須另行說明理由並開立文件。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "外部承包商不能在沒有妳同意與正式程序下取得原件。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他說了「自願」。說了「不是扣押」。說了「外部承包商不能取得原件」。這些是程序語言。也是保護。我要記住每一句。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她點頭。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我同意在場拍照。表面觀察。尺寸與重量記錄。以斜光確認刮痕。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "以及向供應商展示去識別化的預約頁裁切圖與鏡背裁切照片。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她頓了一下。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我不同意將原件交給研究中心或 TKS。不同意無期限留置。不同意破壞性檢查。不同意將研究頁完整個資交給外部公司。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "了解。這些會記錄在案。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她從背包裡拿出封袋。放在桌上。沒有推過去。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯它還在我這邊。等他們記錄完，我再放手讓他們看。不是交出去。是讓他們在我在場的時候看。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "刑警先拿出手機。打開一份去識別化的截圖。第二階段預約頁。姓名欄被遮蔽。住址欄被遮蔽。只留下右上角那行代碼。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "G07／12。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "刑警在表格上寫——", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "第二階段預約頁代碼：G07／12。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他看向封袋裡的鏡子。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "可以拿出來嗎？", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "可以。請戴手套。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "刑警戴上棉手套。把鏡子從封袋裡取出來。放在桌上。正面朝上。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他拿起相機。拍正面。拍背面。拍側面。每一面兩張。閃光燈沒有開。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他拿出一把尺。量尺寸。寫在表格上。七點二公分。四點八公分。零點六公分。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他拿出小型電子秤。量重量。三十八公克。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯和我量的完全一樣。它沒有在路途中被碰過。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他關掉頭頂的日光燈。拿出一支斜光手電筒。從側面照鏡背。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "刮痕在斜光下浮起來。細的。淺的。方向不一致。有的像直線。有的像彎鉤。不能一眼讀成任何完整的字。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "鏡背存在多道人為刻痕。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在表格上寫。很慢。像在選字。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "部分筆畫與上述代碼局部相符。完整內容無法單由刻痕判定。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他沒有寫「鏡背刻有 G07／12」。他寫的是「部分筆畫局部相符」。完整內容無法判定。這是正確的。鏡背不能單獨還原那串字。清晰的來源是預約頁。不是鏡子。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "刑警把斜光關掉。日光燈重新亮起。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "這些刻痕是妳弟弟留下的？", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我不知道。我只知道他失蹤前把鏡子留給我。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音很平。沒有升高。沒有發抖。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "妳知道預約頁上的代碼是什麼？", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我只知道它出現在他的第二階段預約頁。也可能和鏡背刻痕有關。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不說其他孩子。不說 G07 管理群。不說零六點十三分。不說第七曙光。不說千田。不說時間循環。不說我懷疑研究碼和警報系統相連。只說到這裡。剛好夠。不多。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "刑警把表格推過來。指著最後一欄。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "這是妳的陳述紀錄。請確認內容。有需要更正的地方可以現在說。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪讀了一遍。預約頁代碼 G07／12。鏡背部分筆畫局部相符。完整內容無法單由刻痕判定。物主為朝倉澪。與失蹤者朝倉悠真為姐弟關係。原件未留置。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "內容正確。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她簽名。日期。時間。17:31。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "刑警把鏡子放回封袋。推回她這邊。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "原件今日返還。拍照與記錄已完成。未留置。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯它回來了。一個小時。拍照。測量。斜光。簽名。然後它回到我手裡。沒有被扣留。沒有被交給研究中心。沒有被交給 TKS。我帶它進來，我帶它出去。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把封袋放進背包。拉鏈拉好。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "17:35。門被敲了兩下。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "另一名刑警探頭進來。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "供應商技術人員到了。在技術說明室。可以開始了嗎？", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯小野寺。TKS。他到了。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這不是巧合。承辦人早上就告訴我，今天下午五點，負責說明灣岸同步測試的 TKS 技術人員也會到署。我選了十七點。我刻意把有限資訊放到供應商眼前。我要看他的第一反應。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站起來。把背包背上。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "可以。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她跟著刑警走出物件確認室。走廊很長。日光燈把地面照得很白。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯鏡子在我背上。預約頁裁切圖在刑警手裡。等一下，那串 G07／12 會被放到一個陌生人的眼前。一個 TKS 的工程師。一個每天用那種格式的人。我要看他認不認得它。我要看他認出來之後，臉上出現什麼。", background: Background.Chapter_13_Ch13_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "技術說明室的門在走廊盡頭。門上貼著一張白底標籤。", background: Background.Chapter_13_Ch13_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走過去。", background: Background.Chapter_13_Ch13_Act2_S0 },
];
